259	export async function getItemTargetPath(
260	  config: Config,
261	  item: Pick<z.infer<typeof registryItemSchema>, "type">,
262	  override?: string
263	) {
264	  if (override) {
265	    return override
266	  }
267	
268	  if (item.type === "registry:ui") {
269	    return config.resolvedPaths.ui ?? config.resolvedPaths.components
270	  }
271	
272	  const [parent, type] = item.type?.split(":") ?? []
273	  if (!(parent in config.resolvedPaths)) {
274	    return null
275	  }
276	
277	  return path.join(
278	    config.resolvedPaths[parent as keyof typeof config.resolvedPaths],
279	    type
280	  )
281	}
