This is almost identical to the `new-york-v4` version with these differences:
- Import path: `@/registry/bases/radix/lib/utils`
- `cn-` prefixed class names on the outermost element of each sub-component
- Tailwind v4 short data selectors: `data-horizontal:` instead of `data-[orientation=horizontal]:`, `data-active:` instead of `data-[active]:`, `data-completed:` instead of `data-[completed]:`
- `group-data-horizontal/stepper:` instead of `group-data-[orientation=horizontal]/stepper:`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// --- Root Context ---

interface StepperContextValue {
  value: number
  onValueChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 1,
  onValueChange: () => {},
  orientation: "horizontal",
})

// --- Item Context ---

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

// --- Stepper ---

function Stepper({
  className,
  value,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue ?? 1)
  const activeStep = value !== undefined ? value : internalValue

  const handleChange = React.useCallback(
    (step: number) => {
      if (value === undefined) setInternalValue(step)
      onValueChange?.(step)
    },
    [value, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value: activeStep, onValueChange: handleChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex gap-2 data-horizontal:flex-row data-horizontal:items-start data-vertical:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// --- StepperItem ---

function StepperItem({
  className,
  step,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = React.useContext(StepperContext)
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex items-center group-data-horizontal/stepper:flex-col group-data-vertical/stepper:flex-row",
          className
        )}
        role="listitem"
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// --- StepperTrigger ---

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = React.useContext(StepperContext)
  const itemCtx = React.useContext(StepperItemContext)
  const step = itemCtx?.step ?? 0
  const isActive = itemCtx?.isActive ?? false
  const isCompleted = itemCtx?.isCompleted ?? false

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-active={isActive ? "" : undefined}
      data-completed={isCompleted ? "" : undefined}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(step)}
      className={cn(
        "cn-stepper-trigger inline-flex cursor-pointer items-center justify-center rounded-full border-2 border-border bg-background text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 data-active:border-primary data-active:bg-primary data-active:text-primary-foreground data-completed:border-primary data-completed:bg-primary data-completed:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// --- StepperTitle ---

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// --- StepperDescription ---

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// --- StepperSeparator ---

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      role="presentation"
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border group-data-horizontal/stepper:h-px group-data-horizontal/stepper:w-full group-data-horizontal/stepper:flex-1 group-data-vertical/stepper:h-full group-data-vertical/stepper:w-px group-data-vertical/stepper:flex-1",
        className
      )}
      {...props}
    />
  )
}

// --- StepperContent ---

function StepperContent({
  className,
  step: stepProp,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step?: number
}) {
  const { value } = React.useContext(StepperContext)
  const itemCtx = React.useContext(StepperItemContext)
  const step = itemCtx?.step ?? stepProp

  if (step === undefined || value !== step) return null

  return (
    <div
      data-slot="stepper-content"
      role="region"
      className={cn("cn-stepper-content mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
