# Plan: Add Stepper Compound Component to shadcn/ui

## Context

The codebase is a shadcn/ui v4 monorepo (`apps/v4/`). New UI components must be registered in **two parallel registries** that serve different architectural targets:

1. **`new-york-v4`** — the classic shadcn/ui registry, served at `ui.shadcn.com/r/styles/new-york-v4/`
2. **`bases/radix`** — the newer multi-style registry used with the design-system builder

The Stepper component doesn't wrap any Radix UI primitive (no Radix stepper exists), so it is built entirely with React context. This makes both implementations nearly identical — differing only in import paths, Tailwind selector syntax, and `cn-` prefix class naming.

---

## Architecture

### Two-level React Context

```
StepperContext (root)          — value, onValueChange, orientation
  └── StepperItemContext (per-item) — step, isActive, isCompleted (nullable default)
```

`StepperItemContext` defaults to `null` (typed `StepperItemContextValue | null`). This lets `StepperContent` distinguish between "nested inside a StepperItem" (reads item context) vs "used standalone with a `step` prop" (reads root context directly).

### Controlled / Uncontrolled State

Implemented in `Stepper` root component via local `useState` initialized from `defaultValue ?? 1`. When `value` prop is supplied, the external value wins. `onValueChange` fires on every change regardless.

### Orientation

- `data-orientation={orientation}` on every container and separator
- **`new-york-v4`**: `data-[orientation=horizontal]:flex-row`, `group-data-[orientation=horizontal]/stepper:flex-col`
- **`bases/radix`**: `data-horizontal:flex-row`, `group-data-horizontal/stepper:flex-col` (Tailwind v4 short form)

---

## Files to Create (4 new files)

### 1. `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

interface StepperContextValue {
  value: number
  onValueChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 1,
  onValueChange: () => {},
  orientation: "horizontal",
})

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function Stepper({
  className,
  value,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue ?? 1)
  const activeStep = value !== undefined ? value : internalValue

  const handleChange = React.useCallback(
    (step: number) => {
      if (value === undefined) setInternalValue(step)
      onValueChange?.(step)
    },
    [value, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value: activeStep, onValueChange: handleChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  className,
  step,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { value } = React.useContext(StepperContext)
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        role="listitem"
        className={cn(
          "group/stepper-item flex items-center group-data-[orientation=horizontal]/stepper:flex-col group-data-[orientation=vertical]/stepper:flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = React.useContext(StepperContext)
  const itemCtx = React.useContext(StepperItemContext)
  const step = itemCtx?.step ?? 0
  const isActive = itemCtx?.isActive ?? false
  const isCompleted = itemCtx?.isCompleted ?? false

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-active={isActive ? "" : undefined}
      data-completed={isCompleted ? "" : undefined}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(step)}
      className={cn(
        "inline-flex cursor-pointer items-center justify-center rounded-full border-2 border-border bg-background text-sm font-medium transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[completed]:border-primary data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        "data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      role="presentation"
      aria-hidden="true"
      className={cn(
        "shrink-0 bg-border",
        "group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=horizontal]/stepper:w-full",
        "group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:flex-1 group-data-[orientation=vertical]/stepper:h-full",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  step: stepProp,
  children,
  ...props
}: React.ComponentProps<"div"> & { step?: number }) {
  const { value } = React.useContext(StepperContext)
  const itemCtx = React.useContext(StepperItemContext)
  const step = itemCtx?.step ?? stepProp

  if (step === undefined || value !== step) return null

  return (
    <div
      data-slot="stepper-content"
      role="region"
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

