        <StepperItem step={3} className="flex-1">
          <StepperTrigger className="size-8">3</StepperTrigger>
          <StepperTitle className="mt-2">Review</StepperTitle>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperWithContent() {
  const [step, setStep] = React.useState(1)
  return (
    <Example title="With Content">
      <div className="flex w-full flex-col gap-4">
