  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/radix/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper>
      <StepperBasic />
      <StepperWithContent />
      <StepperVertical />
      <StepperControlled />
    </ExampleWrapper>
  )
}

function StepperBasic() {
  return (
    <Example title="Basic">
      <Stepper defaultValue={2} className="w-full">
        <StepperItem step={1} className="flex-1">
          <StepperTrigger className="size-8">1</StepperTrigger>
          <StepperTitle className="mt-2">Account</StepperTitle>
        </StepperItem>
        <StepperSeparator className="mt-4 self-start" />
        <StepperItem step={2} className="flex-1">
          <StepperTrigger className="size-8">2</StepperTrigger>
          <StepperTitle className="mt-2">Profile</StepperTitle>
        </StepperItem>
        <StepperSeparator className="mt-4 self-start" />
        <StepperItem step={3} className="flex-1">
          <StepperTrigger className="size-8">3</StepperTrigger>
          <StepperTitle className="mt-2">Review</StepperTitle>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperWithContent() {
  const [step, setStep] = React.useState(1)
  return (
    <Example title="With Content">
      <div className="flex w-full flex-col gap-4">
        <Stepper value={step} onValueChange={setStep} className="w-full">
          <StepperItem step={1} className="flex-1">
            <StepperTrigger className="size-8">
              {step > 1 ? <CheckIcon className="size-4" /> : "1"}
            </StepperTrigger>
            <StepperTitle className="mt-2">Account</StepperTitle>
          </StepperItem>
          <StepperSeparator className="mt-4 self-start" />
          <StepperItem step={2} className="flex-1">
            <StepperTrigger className="size-8">
              {step > 2 ? <CheckIcon className="size-4" /> : "2"}
            </StepperTrigger>
            <StepperTitle className="mt-2">Profile</StepperTitle>
          </StepperItem>
          <StepperSeparator className="mt-4 self-start" />
          <StepperItem step={3} className="flex-1">
            <StepperTrigger className="size-8">3</StepperTrigger>
            <StepperTitle className="mt-2">Review</StepperTitle>
          </StepperItem>
        </Stepper>
        <div className="rounded-lg border p-4 text-sm">
          <StepperContent step={1}>Create your account.</StepperContent>
          <StepperContent step={2}>Set up your profile.</StepperContent>
          <StepperContent step={3}>Confirm and submit.</StepperContent>
        </div>
        <div className="flex justify-between">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setStep((s) => Math.max(1, s - 1))}
            disabled={step === 1}
          >
            Back
          </Button>
          <Button
            size="sm"
            onClick={() => setStep((s) => Math.min(3, s + 1))}
            disabled={step === 3}
          >
            Next
          </Button>
        </div>
      </div>
    </Example>
  )
}

function StepperVertical() {
  return (
    <Example title="Vertical">
      <Stepper defaultValue={2} orientation="vertical" className="h-48">
        <StepperItem step={1}>
          <StepperTrigger className="size-8">1</StepperTrigger>
          <div className="ml-3 flex flex-col gap-0.5">
            <StepperTitle>Account</StepperTitle>
            <StepperDescription>Create your account</StepperDescription>
          </div>
        </StepperItem>
        <StepperSeparator className="ml-4" />
        <StepperItem step={2}>
          <StepperTrigger className="size-8">2</StepperTrigger>
          <div className="ml-3 flex flex-col gap-0.5">
            <StepperTitle>Profile</StepperTitle>
            <StepperDescription>Set up your profile</StepperDescription>
          </div>
        </StepperItem>
        <StepperSeparator className="ml-4" />
        <StepperItem step={3}>
          <StepperTrigger className="size-8">3</StepperTrigger>
          <div className="ml-3 flex flex-col gap-0.5">
            <StepperTitle>Review</StepperTitle>
            <StepperDescription>Confirm and submit</StepperDescription>
          </div>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperControlled() {
  const [step, setStep] = React.useState(1)
  const totalSteps = 4
  return (
    <Example title="Controlled" containerClassName="col-span-full">
      <div className="flex w-full max-w-xl flex-col gap-6">
        <Stepper value={step} onValueChange={setStep} className="w-full">
          {Array.from({ length: totalSteps }, (_, i) => i + 1).map((n, i) => (
            <React.Fragment key={n}>
              <StepperItem step={n} className="flex-1">
                <StepperTrigger className="size-8">
                  {step > n ? <CheckIcon className="size-4" /> : n}
