            </React.Fragment>
          ))}
        </Stepper>
        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setStep((s) => Math.max(1, s - 1))}
            disabled={step === 1}
          >
            Back
          </Button>
          <Button
            onClick={() => setStep((s) => Math.min(totalSteps, s + 1))}
            disabled={step === totalSteps}
          >
            {step === totalSteps ? "Finish" : "Next"}
          </Button>
        </div>
      </div>
    </Example>
  )
}
