"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// ─── Contexts ────────────────────────────────────────────────────────────────

interface StepperContextValue {
  value: number
  onValueChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 1,
  onValueChange: () => {},
  orientation: "horizontal",
})

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

// ─── Stepper ─────────────────────────────────────────────────────────────────

function Stepper({
  className,
  value,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue ?? 1)
  const activeStep = value !== undefined ? value : internalValue

  const handleChange = React.useCallback(
    (step: number) => {
      if (value === undefined) setInternalValue(step)
      onValueChange?.(step)
    },
    [value, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value: activeStep, onValueChange: handleChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex data-horizontal:flex-row data-horizontal:items-start data-vertical:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

function StepperItem({
  className,
  step,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { value } = React.useContext(StepperContext)
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        role="listitem"
        className={cn(
          "cn-stepper-item group/stepper-item flex items-center group-data-horizontal/stepper:flex-col group-data-vertical/stepper:flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = React.useContext(StepperContext)
  const itemCtx = React.useContext(StepperItemContext)
  const step = itemCtx?.step ?? 0
  const isActive = itemCtx?.isActive ?? false
  const isCompleted = itemCtx?.isCompleted ?? false

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-active={isActive ? "" : undefined}
      data-completed={isCompleted ? "" : undefined}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(step)}
      className={cn(
        "cn-stepper-trigger inline-flex cursor-pointer items-center justify-center rounded-full border-2 border-border bg-background text-sm font-medium transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-completed:border-primary data-completed:bg-primary data-completed:text-primary-foreground",
        "data-active:border-primary data-active:bg-primary data-active:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

