        "cn-stepper-separator shrink-0 bg-border",
        "group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1 group-data-horizontal/stepper:w-full",
        "group-data-vertical/stepper:w-px group-data-vertical/stepper:flex-1 group-data-vertical/stepper:h-full",
        className
      )}
      {...props}
    />
  )
}

